"""
MKT Context Commentary — Psalms chapters 37–40
Run: python3 scripts/zc-context-psalms-37-40.py

Source data used:
- data/interlinear/psalms.json
- data/translation/draft/mediating/psalms.json (MKT text)
- data/commentary/ellicott/psalms.json (philological background)
- data/commentary/jfb/psalms.json (historical context)

Key decisions in this range:
- Ps 37: full alphabetic acrostic (each two-verse strophe opens with successive Hebrew letter);
  wisdom psalm on theodicy; "meek inherit the earth" (v11) quoted verbatim in Matt 5:5;
  4QpPs37 (Qumran Psalms Pesher) applied this psalm messianically — the Teacher of Righteousness
  as the righteous man, the Wicked Priest as the wicked who flourishes then falls
- Ps 38: one of the seven traditional penitential psalms (6, 32, 38, 51, 102, 130, 143);
  lĕhazkîr (memorial offering, superscription) connects prayer to the cultic memorial offering;
  ANE medicine did not separate physical illness from divine judgment — Deut 28 lists disease
  among covenant curses; vv 13-14 chosen silence echoes Isa 53:7 Servant motif
- Ps 39: directed to Jeduthun, a Levitical musician (1 Chr 25:1-6); ḥebel (breath/vanity)
  vocabulary directly parallels Ecclesiastes; v12 ger and tôšāb = legal resident alien pair,
  same self-description Abraham uses (Gen 23:4; Lev 25:23; 1 Chr 29:15)
- Ps 40: hybrid thanksgiving + lament (vv 1-10 thanksgiving, vv 11-17 petition);
  vv 6-8 major LXX/MT divergence: MT "opened ears," LXX "a body you have prepared" — Heb 10:5-7
  applies the LXX reading to Christ's incarnation; Ps 40:13-17 = Ps 70 nearly verbatim
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-context for Psalms 37–40 — the great alphabetic wisdom psalm on theodicy (37),
#   the prototypical penitential lament (38), the meditation on mortality and alien status (39),
#   and the composite thanksgiving-lament with its major NT christological application (40).
# CHANGE? If commentary/mkt-context/psalms.json structure changes, update load_comm/save_comm.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-context/psalms.json'));
#   [print(ch, len(d[ch])) for ch in ['37','38','39','40']]"

PSALMS = {
  "37": {
    "1": '<p>Psalm 37 is an extended alphabetic acrostic wisdom poem: each two-verse (or occasionally three-verse) strophe opens with a successive letter of the 22-letter Hebrew alphabet, running from aleph to taw. This carefully crafted structure signals comprehensive treatment of its subject — the problem of the wicked prospering while the righteous suffer, the central theodicy question of the OT wisdom tradition. The poem belongs to the genre of wisdom psalms (also Pss 1, 19, 49, 73, 78, 112, 119, 128, 133) in which the psalmist teaches from experience rather than addressing God in petition or praise. "Of David" (superscription) — the Davidic attribution gives the speaker authority as one who has navigated the very experiences the poem addresses.</p>',
    "2": '<p>"For like grass they will soon be cut down; like green plants they will wither away" — the grass-and-plant metaphor for human transience is foundational to the Psalter\'s theodicy (Pss 90:5-6; 103:15-16; Isa 40:6-8). The metaphor does double work: the grass appears vigorous in spring but is cut before summer ends, so the wicked\'s flourishing prosperity is itself the evidence of its coming end. The short timescale ("soon," <em>mĕhērāh</em>) is the answer to the "how long?" question that underlies the whole poem. Second Temple readers would have read the wither-and-cut imagery through Isa 40\'s "the grass withers, the flower fades, but the word of our God stands forever."</p>',
    "3": '<p>"Trust in the LORD and do good; live in the land (<em>šĕkon-ʾereṣ</em>) and enjoy secure provision (<em>rĕʿēh ʾĕmûnāh</em>)" — the land promise is inseparable from covenant relationship throughout the Psalter and Deuteronomy. <em>Šākan</em> (dwell, tent, tabernacle) is the root from which <em>šĕkînat</em> (divine presence/dwelling) derives; to dwell in the land is to participate in YHWH\'s dwelling with Israel. <em>Rĕʿēh ʾĕmûnāh</em> is rendered "enjoy secure provision" in the MKT — literally "shepherd faithfulness"; in the pastoral economy, faithful shepherding meant reliable sustenance. The command structure is noteworthy: trust + do good = basis; land-dwelling = result. Deuteronomy\'s land theology is condensed here.</p>',
    "4": '<p>"Find your delight (<em>hiṯʿannag</em>) in the LORD, and he will give you the desires of your heart" — <em>ʿānag</em> (to be delicate, to be soft, to take sensuous delight) is an unusual word typically applied to physical luxury (Isa 55:2; 58:14). The promise that YHWH will give "the desires (<em>mišʾălôt</em>) of your heart" has been misread as a blank-check prosperity promise; in context it is the covenant claim that the one whose delight is in YHWH will find that YHWH himself becomes the desire of the heart — the petition and the answer converge. Augustine\'s <em>our heart is restless until it rests in thee</em> is the theological tradition that reads this correctly.</p>',
    "5": '<p>"Commit (<em>gôl</em>) your way to the LORD" — <em>gālaṭ</em> (roll, commit by rolling onto) gives the physical metaphor: roll your burden onto YHWH as one rolls a heavy stone from a doorway. The same root appears in Prov 16:3 ("commit your works to the LORD") and in the Septuagint\'s rendering of Ps 22:8 ("he committed himself to God"; cited by Matt 27:43 in the mockery of Jesus). "He will bring it to pass (<em>yeʿăśeh</em>)" — the confident assertion of divine efficacy for the one who trusts; not a guarantee of immediate outcome but of ultimate accomplishment of what God wills for the righteous.</p>',
    "6": '<p>"He will bring your righteousness to light (<em>kāʾôr</em>) and your cause bright as noon (<em>kattāhorayim</em>)" — the juridical imagery of divine vindication rendered in light metaphors. In the ancient Israelite legal system, the ultimate court of appeal for the falsely accused was YHWH himself; the divine judge would vindicate the innocent when human courts failed. "Bright as noon" — the metaphor of the noonday sun is the most intense available in a Mediterranean context; what is hidden will be made inescapably visible. Isaiah 58:8 uses the same dawn/noon sequence for the vindication of the fasting community.</p>',
    "7": '<p>"Be still (<em>dôm</em>) before the LORD and wait patiently for him (<em>hityaḥēl</em>)" — two imperatives demanding the opposite of what distress naturally produces. <em>Dāmam</em> (to be still, to be silent, to stop) is also used of the sun standing still (Josh 10:12-13) and of the earth being silent before God (Hab 2:20). <em>Yāḥal</em> (to wait, to hope with expectant patience) is the characteristic verb of the Psalter\'s theodicy response: the righteous wait for YHWH in the face of what seems like inexplicable delay (Pss 25:3, 5, 21; 27:14; 31:24; 33:20; 38:15; 39:7). The command "do not resent the one who prospers" targets the inner attitude (resentment, envy, fretting) as the primary spiritual danger of theodicy situations.</p>',
    "8": '<p>"Let go of anger (<em>ʿereṣ</em>) and abandon wrath (<em>ḥēmāh</em>); do not fret (<em>titḥār</em>)—it leads only to evil" — three parallel commands addressing the inner life during the experience of seeming injustice. <em>Ḥēmāh</em> (rage, burning wrath, also poison/venom) connects the internal experience of anger with the lethal potential of snake venom — both burn and destroy from within. <em>Ḥārar</em> (fret, chafe, be hot) is the same root as the fever-heat of burning; fretting at injustice overheats the soul. The paradox of the verse: the natural response to the wicked prospering is hot anger, but this anger is itself the spiritual danger ("leads only to evil") — it replicates the wicked\'s destructive spirit in the righteous.</p>',
    "9": '<p>"For the wicked will be cut off (<em>yikkārētû</em>), but those who wait for the LORD (<em>qôwê YHWH</em>) will inherit the earth (<em>yîrĕšû-ʾāreṣ</em>)" — the covenant land-inheritance promise deployed as the theodicy resolution. <em>Qāwāh</em> (to wait with hope, to collect strength like a cord drawn taut) is the virtue of patient expectation; Isaiah uses it for those who "renew their strength" (Isa 40:31). The land-inheritance theology runs from the patriarchal covenant (Gen 15:7; 17:8) through Deuteronomy\'s obedience-blessing-land structure (Deut 4:1; 6:18; 16:20) to the Psalter\'s eschatological use: the "earth" (or "land," <em>ʾāreṣ</em>) inherited by the righteous is simultaneously the promised land and the creation itself.</p>',
    "10": '<p>"In just a little while (<em>ʿôd meʿaṭ</em>) the wicked will be gone; you will search for his place, but it will not be found" — the "little while" is a wisdom assertion about historical time, not a precise prediction. Hab 2:3 uses similar temporal language: "the revelation awaits an appointed time; if it seems slow, wait for it." The searching-and-not-finding motif is the complete erasure of trace — not merely gone but untraceable. In ANE thought, the ultimate defeat was to have no place, no land, no memorial, no offspring to remember you (the root of the "cut off" language). The verse closes the theodicy circle: what the wicked sought to take from the righteous (place, inheritance, future) is precisely what the wicked loses.</p>',
    "11": '<p>"But the meek (<em>ʿănāwîm</em>) will inherit the earth and delight in abundant peace (<em>šālôm</em>)" — the central verse of the entire psalm, made famous by Jesus\'s quotation in the third Beatitude (Matt 5:5). The <em>ʿănāwîm</em> (meek, humble, poor in spirit) are those who have chosen not to take, grab, or scheme — the antithesis of the wicked who "scheme" (v. 12), "draw the sword" (v. 14), and "borrow without repaying" (v. 21). In Second Temple Judaism, the <em>ʿănāwîm</em> became a technical term for the pious remnant, the community that trusted YHWH rather than political alliances or violence (cf. Zeph 2:3; 3:12; Isa 61:1). The Qumran community likely saw themselves as the <em>ʿănāwîm</em> of this psalm, awaiting their eschatological inheritance.</p>',
    "12": '<p>"The wicked man schemes (<em>zômēm</em>) against the righteous and grinds his teeth (<em>ḥāraq šinnayim</em>) at him" — the paired acts of the wicked: inner scheming and outward physical contempt. <em>Zāmam</em> (to plan, scheme, devise) in the legal context means to prepare false testimony — a scheming witness (Deut 19:19). "Grinding the teeth" is the gesture of aggressive rage that the Psalter records as the enemy\'s response to the righteous person\'s trust and blessing (Pss 35:16; 112:10; Lam 2:16; Acts 7:54 — the Sanhedrin grinds teeth at Stephen\'s speech). The bodily expression of hatred makes the wicked\'s inner scheming visible in a gesture that could be observed by the community.</p>',
    "13": '<p>"The Lord laughs at the wicked, for he sees that their day is coming" — divine laughter at the wicked is one of the Psalter\'s most striking theological assertions (Ps 2:4 — YHWH laughs at conspiring kings; Ps 59:8). The laughter is not casual amusement but the triumphant confidence of the one who holds final authority: the wicked\'s apparent power is from the divine perspective already a settled matter. "His day is coming (<em>yômô bāʾ</em>)" — the day of reckoning and judgment. "Day" (<em>yôm</em>) language for divine judgment appears throughout the prophets (Isa 13:6; Jer 46:10; Ezek 30:3; Joel 2:1; Amos 5:18) as the "Day of the LORD" — the day when YHWH\'s rule becomes inescapably visible.</p>',
    "14": '<p>"The wicked draw the sword and bend their bow to bring down the poor (<em>ʿānî</em>) and helpless (<em>ʾebyôn</em>)" — the two most common OT designations for the socially vulnerable are paired: <em>ʿānî</em> (the poor, the afflicted, those without social resources) and <em>ʾebyôn</em> (the needy, those in genuine material want). The combination identifies the targets of the wicked\'s armed aggression as those with no military or social means to resist. In the ancient Israelite society, armed violence against the poor was the greatest moral offense against the covenant order — the prophets (Amos 2:6-7; 8:4-6; Isa 10:1-2; Mic 2:1-2) make this the primary charge against Israel\'s ruling class.</p>',
    "15": '<p>"Their swords will pierce their own hearts, and their bows will be shattered" — the boomerang principle of retributive justice, in which the instrument of harm turns against its wielder (Pss 7:15-16; 9:15-16; 35:8; Prov 26:27; Eccl 10:8). The sword-that-pierces-the-heart is the most intimate form of this reversal: the weapon carried against another ends up in the carrier\'s own chest. This retributive pattern — the wicked destroyed by their own schemes — is one of the Psalter\'s fundamental theological convictions about the moral order of the universe, rooted in the character of the God who oversees it.</p>',
    "16": '<p>"Better is the little that the righteous has than the great wealth of many wicked" — the "better than" (<em>ṭôb … min</em>) form is characteristic of the wisdom tradition\'s comparative aphorisms (Prov 15:16-17; 16:8, 19; 17:1; 19:1, 22; 21:9; 25:7, 24; Eccl 4:6; 9:16). The comparison challenges the ANE and universal assumption that wealth = blessing. In the covenant theology of the Psalter, what the righteous has — relationship with YHWH, integrity, covenant faithfulness — exceeds in value any quantity of material wealth held by those outside the covenant. This verse is the wisdom-psalm equivalent of Jesus\'s "what does it profit a man to gain the whole world and forfeit his soul?" (Mark 8:36).</p>',
    "17": '<p>"For the strength of the wicked will be shattered, but the LORD supports (<em>sômēk</em>) the righteous" — <em>sāmak</em> (to support, to lean on, to uphold) is the verb used for laying hands on the head of the sacrificial animal (Lev 1:4; 3:2; 4:4) and for taking an oath by laying hands on a person (Lev 24:14). The divine supporting hand on the righteous is thus both a sustaining grip and a covenantal identification. The antithesis with the wicked\'s "strength (<em>zĕrôʿôt</em>) being shattered" — the arm/shoulder as the symbol of military power being broken — echoes Ps 10:15; 37:37; Isa 40:10.</p>',
    "18": '<p>"The LORD knows (<em>yôdēaʿ</em>) the days of the upright, and their inheritance will last forever" — divine knowledge of "the days" is not merely temporal awareness but intimate engagement: YHWH knows the days of the righteous as a shepherd knows his flock or a parent knows a child. "Their inheritance will last forever (<em>lĕʿôlām tihyeh naḥălāṯām</em>)" — the covenant land inheritance is given eschatological scope: it is not merely a historical possession subject to exile and loss but an eternal endowment. This is the Psalter\'s answer to the Assyrian and Babylonian destructions: the exile cannot be the final word because the righteous\'s inheritance is eternal.</p>',
    "19": '<p>"They will not be disgraced in days of trouble (<em>bĕʿēt rāʿāh</em>); in times of famine (<em>bîmê rāʿāb</em>) they will be satisfied" — two specific crisis scenarios: unspecified trouble (war, social upheaval, persecution) and famine. Famine was the recurrent catastrophe of ancient Near Eastern life, striking every few years in the grain-dependent agrarian economies of Palestine and Mesopotamia. The promise of satisfaction "in famine" is the covenant provision of Deut 28:12 and its anti-type in the curse list (Deut 28:22-24, 38-42). In Joseph\'s narrative, YHWH uses Joseph to provide grain in Egypt during the very famine that would have destroyed the covenant family — the divine care in famine is a historical type the Psalter assumes.</p>',
    "20": '<p>"The wicked will perish; the enemies of the LORD will fade like green pastures (<em>kîqar kārîm kālû</em>)" — a difficult phrase; some manuscripts and the Septuagint read differently. The MKT follows "green pastures" — the lush spring grass that disappears in summer heat. "They will dissolve, consumed like smoke" — the smoke metaphor for complete and rapid dissolution appears in Ps 68:2 ("as smoke is driven away"); Isa 51:6 ("the heavens will vanish like smoke"). The three images — fading grass, dissolving smoke, perishing enemies — reinforce the central theodicy claim: the wicked\'s apparent permanence is illusory; their dissolution is as natural and complete as summer\'s end.</p>',
    "21": '<p>"The wicked borrows and does not repay, but the righteous is generous and gives" — the economic behavior of the wicked versus the righteous as moral indicators. In ancient Israelite society, lending was a covenant obligation: the Torah prohibited lending at interest to fellow Israelites (Exod 22:25; Lev 25:36-37; Deut 23:19-20) and required loans to the needy as acts of covenant solidarity. The wicked who borrows and does not repay violates both the economic trust (a contract broken) and the covenantal ethic (taking from the poor without reciprocity). The righteous who is "generous and gives" (<em>ḥônēn ûmalbēš</em>) enacts the covenant character of YHWH himself (cf. Ps 112:5; Prov 19:17; 28:27).</p>',
    "22": '<p>"Those blessed by the LORD will inherit the earth, but those he has cursed will be cut off" — the deuteronomic blessing-curse structure stated in its starkest form. The Abrahamic covenant is the paradigm: "I will bless those who bless you, and those who dishonor you I will curse" (Gen 12:3). In the Psalter, the categories of "blessed" and "cursed" are not arbitrary divine preferences but the natural outcomes of alignment with or opposition to the covenant order. "Cut off (<em>yikkārētû</em>)" — the covenant legal penalty for violations of the most serious covenant obligations (Exod 12:15, 19; 30:33, 38; 31:14; Lev 7:20-27), meaning exclusion from the covenant community and its future.</p>',
    "23": '<p>"The LORD establishes (<em>mēkônān</em>) the steps of a man and delights (<em>yehpāṣ</em>) in his way" — <em>kûn</em> (to establish, to make firm, to prepare) is used for YHWH\'s establishment of creation (Pss 96:10; 119:90), of the throne (1 Sam 13:13; 2 Sam 7:13), and of the human steps within the covenant path. The pairing with divine delight (<em>ḥāpēṣ</em>) makes the relationship intimate rather than merely administrative: YHWH takes pleasure in the covenant-aligned human\'s journey. This is the divine-shepherd-of-the-individual motif in its wisdom form, parallel to Ps 23\'s "he guides me in the paths of righteousness" and Prov 3:6 "he will make straight your paths."</p>',
    "24": '<p>"Though he stumbles (<em>yippōl</em>), he will not fall headlong (<em>yûṭāl</em>), for the LORD holds (<em>sômēk</em>) his hand" — the two-stage description of the righteous person\'s fall differentiates stumbling (the inevitable failures of the good) from headlong collapse (the final ruin of the wicked). The divine hand holding (<em>sāmak</em>) — the same supporting verb as v. 17 — is what converts the stumble into recovery rather than fall. In Second Temple Judaism, Prov 24:16 reinforced this teaching: "for the righteous falls seven times and rises again, but the wicked stumble into calamity." The divine-held-hand motif is one of the Psalter\'s most intimate anthropomorphisms.</p>',
    "25": '<p>"I was young and now I am old, yet I have never seen the righteous abandoned (<em>neʾĕzāb</em>) or their children begging for food" — the appeal to personal biography as wisdom evidence. ANE wisdom literature regularly cited the sage\'s lifetime observation as the basis for instruction (Prov 4:3-4; 7:6-7; 24:32; Eccl 1:12-14; Sir 51:13-22). The claim is not empirical-universal but covenantal: the psalmist is not asserting that no righteous person has ever suffered want (Elijah fled into the desert hungry; Paul goes hungry in 2 Cor 11:27) but that YHWH\'s pattern of provision for the covenant-faithful is consistent enough to be called never-having-seen. The community memory of divine faithfulness is the basis of present trust.</p>',
    "26": '<p>"He is always generous and lending (<em>ûmalweh</em>), and his children become a blessing (<em>lĕbĕrākāh</em>)" — the righteous person\'s generosity cascades across generations: his children become a blessing to others, continuing the chain of covenant kindness. "His children become a blessing" echoes the Abrahamic covenant formula: "you will be a blessing" (Gen 12:2) and "in your offspring all nations will be blessed" (Gen 22:18). The righteous person\'s life functions, in miniature, as the fulfillment of the Abrahamic mission: to be a source of blessing to the surrounding world.</p>',
    "27": '<p>"Turn away from evil (<em>sûr mērāʿ</em>) and do good, so you will live in the land permanently" — the ethical summary of the psalm\'s entire teaching compressed into an imperative couplet. <em>Sûr mērāʿ</em> (turn away from evil) appears in Ps 34:14 in almost identical form, and in Job 1:1, 8; 2:3 as the definition of Job\'s righteousness ("blameless and upright, one who feared God and turned away from evil"). "Live in the land permanently (<em>lĕʿôlam šĕkon</em>)" — the land-dwelling permanence of the covenant obedient is the Psalter\'s answer to the historical fact of exile. The covenant promise is not revoked by historical catastrophe but awaits its eschatological fulfillment.</p>',
    "28": '<p>"For the LORD loves justice (<em>mišpāṭ</em>); he does not abandon (<em>lōʾ-yaʿăzōb</em>) his faithful people (<em>ḥăsîdāyw</em>)" — the three divine attributes that constitute the psalm\'s theodicy resolution: justice-love, non-abandonment, and faithful-ones-protection. <em>Ḥāsîd</em> (faithful one, pious one, loyal one) — the corresponding human term to divine <em>ḥesed</em> (steadfast love, covenant loyalty); the <em>ḥăsîdîm</em> are those who reciprocate divine covenant loyalty with their own loyalty. "The offspring of the wicked will be cut off (<em>wĕzereʿ rĕšāʿîm nikkĕrāṯ</em>)" — the generational contrast: the righteous\'s children are "a blessing" (v. 26) while the wicked\'s offspring are "cut off," ending the family line.</p>',
    "29": '<p>"The righteous will inherit the earth (<em>ʾereṣ</em>) and make their home in it forever" — the third occurrence of the land-inheritance promise in the psalm (vv. 9, 11, 29), creating an emphatic structural refrain. The eschatological scope intensifies at each repetition: "inherit the earth" and "make their home in it forever (<em>lĕʿôlam</em>)" push the promise beyond the historical promised land into the apocalyptic new creation. Isaiah 65:17-25 and 66:22 use similar language for the eschatological new earth. The NT citation (Matt 5:5) reads this precisely in its eschatological register — the meek do not merely settle in Canaan but receive the renewed earth of the age to come.</p>',
    "30": '<p>"The righteous speak wisdom (<em>yehgeh ḥokmāh</em>), and their tongue talks of justice (<em>mišpāṭ</em>)" — the inner character of the righteous is expressed in the quality of their speech. <em>Hāgāh</em> (to mutter, to meditate, to murmur) is used for the constant inner speech of one who meditates on Torah (Ps 1:2; Josh 1:8). The righteous person\'s mouth is filled with wisdom and justice because those are the categories that dominate his inner life. Wisdom literature\'s speech ethics: James 3\'s "the tongue is a fire" is the NT continuation of this tradition — the quality of speech as the measure of the inner person (Prov 10:11, 13-14, 18-21; 12:17-19; Matt 12:34).</p>',
    "31": '<p>"The law (<em>tôrat</em>) of his God is in his heart (<em>lēb</em>); his steps do not falter" — the internalization of Torah is the Psalter\'s ideal of righteous formation. Deut 6:6 ("these words shall be in your heart") and Jer 31:33 ("I will put my law within them, and I will write it on their hearts") both describe the same internalization. In Ps 119, the 176-verse meditation on Torah, the same claim is central (Ps 119:11: "I have hidden your word in my heart that I might not sin against you"). The practical result of internalized Torah is stability: "his steps do not falter (<em>lōʾ timlāḍ ʾăšurāyw</em>)," reversing the "slippery path" prepared for the wicked (Ps 35:6).</p>',
    "32": '<p>"The wicked lie in wait for the righteous, looking to kill them (<em>lĕhamîtô</em>)" — the ambush metaphor for legal and social conspiracy returns (cf. Ps 10:8-9 — the wicked ambush like a lion; 35:7 — the net and pit of the conspirator). The legal context is prominent: the accusers who "lie in wait" are preparing false testimony; the "killing" may be social and legal — destroying the righteous person\'s reputation, property, and legal standing — rather than literal assassination. In the ancient world, legal destruction was as final as physical death: it ended a person\'s ability to function in the community.</p>',
    "33": '<p>"The LORD will not leave the righteous at the mercy (<em>lĕyādô</em>) of the wicked or let them be condemned at trial (<em>bĕhiššāpĕṭô</em>)" — the legal and divine dimensions converge: YHWH will not leave the righteous "in the hand" (legal power) of the wicked, and will not condemn them "when he [the righteous] is tried." Both clauses address the same danger from two sides. The divine guarantee of courtroom vindication is the prayer of every accused innocent in the Psalter (Pss 7:8; 26:1; 35:23-24; 43:1; 109:31). YHWH as the ultimate court is the theodicy resolution of the entire Psalm 37: the verdicts of human courts are not final; the divine tribunal overrules them.</p>',
    "34": '<p>"Wait for the LORD and keep his way (<em>šĕmōr darkô</em>); he will exalt you to inherit the earth. You will be there to see the wicked cut off" — the personal witness to divine vindication: the patient righteous will live to see what they were promised. "Keep his way" echoes Deut 8:6; 10:12; 11:22; 19:9 — the covenant path that leads to covenant blessing. "You will be there to see" (<em>wĕrāʾîṯā</em>) — the personal, embodied witness to divine justice; the righteous will not merely hear about the fall of the wicked but will see it themselves. This is the eschatological witness motif: those who have waited in faith will be vindicated by what they observe in the final settlement.</p>',
    "35": '<p>"I have seen a ruthless wicked man (<em>ʾārîṣ</em>) towering like a flourishing tree in its native ground (<em>mitraʿănān kĕʾezrāḥ raʿănān</em>)" — the tree metaphor for the wicked\'s flourishing reverses the blessed person\'s tree image in Ps 1:3 (the righteous as a tree planted by water). The wicked\'s tree is <em>ʾezrāḥ raʿănān</em> — a "green native tree," well-established in its natural soil, the picture of maximum vitality. The word <em>ʾezrāḥ</em> (native, indigenous, "one who arises from the soil") is the word for natural-born citizens vs. resident aliens — the wicked is rooted, established, the indigenous power. <em>ʾĀrîṣ</em> (ruthless, violent tyrant) is used in Isa 13:11; 49:25 for the aggressive oppressor.</p>',
    "36": '<p>"But he passed away — gone; I looked for him and he could not be found" — the counterpoint to v. 35: the tree that appeared immovable is simply gone. The brevity of the two cola mirrors the brevity of the wicked\'s end. <em>Wayyaʿabōr</em> (and he passed away) — the verb <em>ʿābar</em> (to pass over, to pass through, to go away) is used for the passing of storms, seasons, and life. The inability to find the place of the wicked echoes v. 10 ("you will search for his place, but it will not be found") and the erasure of the wicked\'s trace. The autobiographical form ("I looked for him") makes the theodicy claim a personal testimony rather than abstract doctrine.</p>',
    "37": '<p>"Take note of the blameless person (<em>ṯāmîm</em>) and look at the upright (<em>yāšār</em>); the future of such a person is peace (<em>šālôm</em>)" — the penultimate section\'s positive portrait, in contrast to the tree-and-gone portrait of the wicked. <em>Tāmîm</em> (blameless, complete, whole) — the same word used of Noah (Gen 6:9), Abraham (Gen 17:1), and Job (Job 1:1, 8); it denotes covenantal integrity, not moral perfection. "Future (<em>ʾaḥărît</em>)" — the future, the end-outcome, the final state; the wisdom tradition was preoccupied with the contrast between the <em>ʾaḥărît</em> of the righteous and the <em>ʾaḥărît</em> of the wicked (Prov 23:18; 24:14, 20; Jer 17:11). "Peace (<em>šālôm</em>)" as the telos of the righteous life: not merely absence of conflict but wholeness, completion, the fulfillment of the human covenant vocation.</p>',
    "38": '<p>"But rebels (<em>pōšĕʿîm</em>) will all be destroyed together; the future (<em>ʾaḥărît</em>) of the wicked will be cut off" — <em>pešaʿ</em> (rebellion, transgression) denotes specifically the willful, defiant violation of covenant relationship — not inadvertent failure but deliberate breach. The term is used in prophetic indictments of Israel\'s willful apostasy (Amos 1-2; Isa 1:2, 28; 53:5, 8, 12). "Together (<em>yaḥdāw</em>)" — the solidarity of the wicked in destruction mirrors their solidarity in scheming (v. 12); they conspired together and will be destroyed together. "Future cut off" (same <em>ʾaḥărît</em> as v. 37) — the stark antithesis: <em>šālôm</em> versus erasure.</p>',
    "39": '<p>"The salvation (<em>tĕšûʿāh</em>) of the righteous comes from the LORD; he is their stronghold (<em>māʿûzzām</em>) in times of trouble" — the psalm moves toward its conclusion with a compact summary of covenant theology. <em>Tĕšûʿāh</em> (salvation, deliverance, victory) is the verbal noun of <em>yāšaʿ</em> (to save, to deliver), the root of the names Joshua and Jesus. <em>Māʿûz</em> (stronghold, fortress, refuge) — the same military architecture metaphor used throughout the Psalter for YHWH as the fortified city protecting those who shelter within (Pss 27:1; 28:8; 31:2, 4; Nah 1:7). The combination of <em>tĕšûʿāh</em> and <em>māʿûz</em> captures both the active rescue and the passive protection dimensions of divine salvation.</p>',
    "40": '<p>"The LORD helps (<em>yaʿzĕrēm</em>) and delivers them (<em>wĕyĕpallĕṭēm</em>); he rescues them from the wicked and saves them, because they take shelter (<em>ḥāsû</em>) in him" — the final verse of the acrostic summarizes in four verbs the divine activity: help, deliver, rescue, save. The final condition — "because they take shelter in him (<em>kî-ḥāsû bô</em>)" — places the decisive weight not on merit but on trust: what qualifies the righteous for divine rescue is their refuge-taking (the <em>ḥāsāh</em>-shelter verb, also in Pss 2:12; 5:11; 17:7; 25:20; 31:19; 34:22). The acrostic ends with this trust-based refuge as the comprehensive answer to the entire psalm\'s question: how do the righteous survive when the wicked prosper? By sheltering in the God who will ultimately cut the wicked off.</p>',
  },
  "38": {
    "1": '<p>Psalm 38 belongs to the traditional seven penitential psalms of the church (Pss 6, 32, 38, 51, 102, 130, 143), used in Christian liturgy for Ash Wednesday, Holy Week, and seasons of penitence. The superscription <em>lĕhazkîr</em> (as a memorial offering) is unique among the psalm headings — it appears also in Ps 70 (which overlaps with Ps 40:13-17). The <em>mazkîr</em> offering was the memorial portion of the grain offering (<em>minḥāh</em>), the portion burned on the altar as a "remembrance before the LORD" (Lev 2:2, 9, 16; 5:12; 6:15; Num 5:26). By connecting this prayer to the memorial offering, the superscription frames the psalm as a liturgical act of bringing the speaker\'s suffering and sin "before God\'s face" in the same way the incense smoke of the altar rose as a memorial.</p>',
    "2": '<p>"Your arrows have pierced me deeply (<em>nĕḥatû bî ḥiṣṣêkā</em>), and your hand has come down hard on me" — the image of divine arrows as instruments of judgment appears throughout the OT and ANE: in the Ugaritic texts, Baal fights with lightning-bolt arrows; Ps 7:12-13 describes YHWH as an archer preparing arrows against the wicked; in Job 6:4 Job complains "the arrows of the Almighty are in me." The arrows and the heavy hand are two registers of the same experience: precise targeted impact (arrows) and crushing weight (hand). Together they convey that the suffering is experienced as divinely directed, not random misfortune.</p>',
    "3": '<p>"My body has no soundness (<em>ʾên-šālôm</em>) because of your anger; my bones have no rest because of my sin" — the connection between physical illness and divine anger/sin is explicitly stated here, reflecting the ancient Israelite understanding of the body as a psychosomatic unity in which moral and physical states are intertwined. Deuteronomy 28 lists a catalog of diseases (vv. 22, 27-28, 35, 60-61) as covenant curses for disobedience. ANE medicine was not separated from religion: the Babylonian <em>bārû</em> (divination priest) and the Assyrian <em>āšipu</em> (exorcist) diagnosed illness as the result of sin or offense against the deity and prescribed both medical and ritual responses. This is not naive — it reflects a world-view in which physical, moral, and spiritual reality are unified.</p>',
    "4": '<p>"My iniquities have overwhelmed me (<em>ʿābrû rōʾšî</em>) — they are a burden too heavy to carry (<em>kĕmassāʾ kābēd yiḵbĕdû mimenî</em>)" — the weight metaphor for guilt is physically visceral. <em>ʿĀbar rōʾš</em> (to pass over the head) is used elsewhere for floodwaters passing over someone (Ps 69:2; Isa 43:2; Lam 3:54) — the sense of being submerged, overwhelmed. "A burden too heavy to carry (<em>massa kābēd</em>)" — <em>massāʾ</em> (burden, load, oracle) is used for the prophetic oracle (Isa 13:1; Nah 1:1) and for the physical burdens carried by the Levites in the wilderness (Num 4:15, 19, 24-32). The combination creates the picture of sin as an Oracle-burden — both heavy as a physical load and authoritative as a divine pronouncement against the speaker.</p>',
    "5": '<p>"My wounds stink and fester (<em>hĕbîʾšû nāmaqû</em>) because of my own foolishness (<em>ʾiwwaltî</em>)" — the language of festering wounds as a consequence of moral failure is both literal (the speaker is physically ill) and metaphorical (the wound-language carries the moral freight of "my sin stinks before God"). <em>Nāmaq</em> (to putrefy, to decay, to dissolve) is used for the decaying of the slain (Isa 34:4) and the dissolving of flesh (Zech 14:12). <em>ʾIwwelet</em> (foolishness) is the wisdom tradition\'s term for the character defect that leads to moral and practical destruction — the antithesis of <em>ḥokmāh</em> (wisdom). Significantly, the psalmist claims responsibility: "my own foolishness," not YHWH\'s arbitrariness.</p>',
    "6": '<p>"I am bowed low (<em>naʿăwêṯî</em>) and hunched over (<em>šaḥōṯî</em>); I walk about mourning (<em>qōdēr</em>) all day long" — the three postures of the penitent/afflicted are described. <em>ʿĀwāh</em> (to be bent, crooked, bowed) describes the physical manifestation of moral and physical burden. <em>Šāḥāḥ</em> (to bow down, to crouch, to be humiliated) — the verb for the posture of mourning, defeat, and prostration before God or king. <em>Qādar</em> (to be dark, to be in mourning dress, to go about darkly) — the wearing of dark mourning garments (sackcloth) and the resultant darkened appearance of one in mourning. All three terms were observable bodily states in the ancient world: the psalmist\'s inner condition was visible to the community through these postures and dress.</p>',
    "7": '<p>"My loins are on fire with disease (<em>mālĕʾû qalĕqālōṯ</em>), and there is no health anywhere in my body" — <em>qālāl</em> (to be degraded, to be shameful, here possibly "to be feverish/burning") is textually difficult. The loins (<em>kĕsālîm</em>) as the seat of physical strength and vitality (Ps 66:11; Isa 21:3; Job 15:27) — the burning/disease in the loins signals the collapse of the core of physical power. "No health (<em>ʾên tōm</em>) anywhere in my body" — <em>tōm</em> (completeness, soundness, integrity) from <em>tāmam</em> (to be complete); the same word used for Job\'s "integrity" (Job 2:3, 9; 27:5). The psalmist\'s physical integrity has collapsed, mirroring the moral-spiritual collapse of v. 4-5.</p>',
    "8": '<p>"I am benumbed (<em>pūgôṯî</em>) and utterly crushed (<em>nidkêṯî meʾōd</em>); I cry out (<em>šāʾagtî</em>) from the anguish of my heart" — three states of extremity. <em>Pûg</em> (to be numb, to be cold, to faint) — used of the heart "growing cold" in dread (Gen 45:26; Ps 77:2). <em>Dākaʾ</em> (to be crushed, to be pulverized, to be ground down) — the most violent crushing, used for enemies crushed in battle (Ps 143:3; Isa 53:5, 10) and for the brokenhearted whom God is near to (Ps 34:18). <em>Šāʾag</em> (to cry out, to roar like a lion) — the most urgent, desperate vocal cry; used of God "roaring" in judgment (Amos 1:2; Joel 3:16) and of the psalmist in extremity (Ps 22:1).</p>',
    "9": '<p>"Lord, all my longing (<em>taʾăwāṯî</em>) is laid out before you; my groaning (<em>ʾanḥāṯî</em>) is not hidden from you" — the turn from physical description to direct address. <em>Taʾăwāh</em> (longing, desire, appetite) — the same word for the food-longing of the wilderness wanderers (Num 11:4) and the object of Wisdom\'s desire (Prov 13:12). All the psalmist\'s longing is exposed before YHWH — not concealed or reordered into polite petition but "laid out" (<em>negdĕkā</em>, before your face). <em>ʾAnḥāh</em> (groaning, sighing) is the involuntary sound of suffering that exceeds words (Rom 8:26 — the Spirit intercedes with "groanings too deep for words" uses <em>stenagmos</em>, the LXX equivalent of <em>ʾanḥāh</em>).</p>',
    "10": '<p>"My heart pounds (<em>sĕḥarḥar</em>); my strength has failed, and even the light of my eyes has deserted me (<em>ʾên ʾittî</em>)" — <em>sāḥar</em> (to turn around, to revolve, to pound) in the intensive form suggests a heart racing and churning in agitation. "The light of my eyes" — a common idiom for vitality, consciousness, and the joy of living (Pss 13:3; 19:8; Prov 15:30; 1 Sam 14:27, 29). The phrase captures the complete spectrum of collapse: heart (emotional center), strength (physical capacity), and eyes (perceptual vitality) have all failed. The list of physical symptoms in vv. 3-10 is one of the most comprehensive anatomical surveys of suffering in the Psalter.</p>',
    "11": '<p>"My friends and companions keep away (<em>yirḥāqû</em>) from my affliction, and even my relatives (<em>qĕrôbāy</em>) stand at a distance (<em>mibbĕneged</em>)" — the social isolation of illness in the ancient world was severe and systematic. In a culture where illness was interpreted as divine judgment, the sick person was socially dangerous — potentially contagious spiritually as well as physically. Levitical purity law required social isolation for various skin diseases (Lev 13-14), and general practice extended this to other severe illnesses. The psalmist\'s experience mirrors Job\'s: those who should provide comfort and solidarity — friends, companions, relatives — stand at a distance, abandoning the sick person precisely when human presence is most needed. Jesus\'s healing ministry was a deliberate reversal of this pattern.</p>',
    "12": '<p>"Those who want me dead set traps for me; those who seek to harm me speak of my destruction and scheme all day long" — while the psalmist is physically weakened and socially isolated (v. 11), the enemies are actively plotting. The trap metaphor (cf. Pss 9:15; 35:7; 57:6) represents ambush-style conspiracy rather than open confrontation. The enemies\'s timing is strategic: they plot "all day long" (<em>kol-hayyôm</em>) while the psalmist is most vulnerable. This exploitation of illness and social isolation by enemies is a recognizable social pattern: the powerful attacking the sick was condemned by the prophets (Ezek 34:4 — shepherds who exploit the sick sheep rather than healing them).</p>',
    "13": '<p>"But I am like someone who cannot hear — I do not listen; like someone mute (<em>ʾilēm</em>) who cannot speak" — the psalmist\'s response to the plotting enemies is chosen silence — not inability but deliberate restraint. The deaf-and-mute posture is a strategy: by refusing to engage, the psalmist avoids being drawn into a contest he cannot win in his weakened state. Significantly, the same image of sheep-silence before the shearer (Isa 53:7) describes the Servant of the LORD: "he was oppressed and afflicted, yet he did not open his mouth." The resonance between the penitent psalmist and the silent Servant is developed in NT theology as Jesus\'s deliberate silence before his accusers (Mark 14:61; 15:5; Matt 26:63).</p>',
    "14": '<p>"I am like a man who does not hear, with no counter-arguments (<em>tôkāḥôṯ</em>) in his mouth" — <em>tôkēḥāh</em> (proof, refutation, counter-argument) is the legal term for an evidence-based rebuttal: the psalmist has no legal defense prepared. In the ancient Israelite legal setting, the accused was expected to mount a verbal defense; the inability to do so was equivalent to admitting guilt. The psalmist chooses to bring no defense — not because he has no ground to stand on, but because he has laid all his case before YHWH (v. 9) rather than before human accusers. The divine court is the only tribunal that matters.</p>',
    "15": '<p>"But in you, LORD, I place my hope (<em>yāḥaltî</em>); you will answer (<em>taʿăneh</em>), O Lord my God" — the turn of the lament to trust. <em>Yāḥal</em> (to wait with hope, to hope with expectation) — the virtue of patient expectation (cf. Ps 37:7 above). "You will answer" — the conviction that YHWH, unlike the human courts and social network, will respond. This confidence is not based on the speaker\'s innocence (he has confessed his sins, vv. 3-4, 18) but on YHWH\'s covenant character as the one who hears prayer. The shift from the third-person description of enemies to the direct second-person address of YHWH in v. 15 is the pivot of the entire psalm.</p>',
    "16": '<p>"For I thought: Do not let them gloat over me — those who triumph (<em>hăgdîlû</em>) over me when I stumble" — the social-honor dimension: the enemies\' goal is public triumph, the visible reversal of the psalmist\'s social standing. <em>Gādal</em> (to make great, to magnify, to triumph) in this context means the elevation of the enemy\'s status at the psalmist\'s expense — the ancient zero-sum honor game. The fear of the enemy\'s gloating was as real as the fear of physical harm: in an honor-shame culture, social humiliation before the community was a form of death. The psalmist prays to be spared both the physical fall (stumbling) and the social fall (enemies celebrating it).</p>',
    "17": '<p>"For I am about to stumble (<em>lĕṣelāʿ nākon ʾānî</em>) and my pain is always with me (<em>wĕmaḵʾôbî negdî ṯāmîd</em>)" — <em>nākon</em> (prepared, ready, set) with <em>liṣlōaʿ</em> (to stumble, to limp) — the psalmist is "prepared to stumble" — perched at the edge of collapse. "My pain is always before me (<em>negdî</em>)" — the pain is not intermittent or situational but <em>negdî</em> (before my face, constantly present in my perception). The chronic pain of v. 17 connects to the chronic scheming of the enemies in v. 12 ("all day long") — both the internal suffering and the external threat are unrelenting.</p>',
    "18": '<p>"I confess (<em>ʾaggîd</em>) my wrongdoing (<em>ʿăwōnî</em>); I am distressed (<em>ʾedʾag</em>) by my sin (<em>mēḥaṭṭāʾṯî</em>)" — the penitential confession at the center of the psalm. <em>Nāgad</em> (to declare, to report, to confess) in the hiphil is the act of making known what was hidden — the open declaration of sin rather than concealment. <em>ʿĀwōn</em> (iniquity, wrongdoing, guilt) — the broadest term for sin, covering both the act and its consequences. <em>Ḥāṭṭāʾ</em> (sin, failure, missing the mark) — the most common OT term, from <em>ḥāṭāʾ</em> (to miss). Together they cover the full range of human moral failure. "I am distressed by my sin" — the grief over sin is itself a component of repentance in the prophetic tradition (Joel 2:12-13; Isa 66:2).</p>',
    "19": '<p>"But my enemies are full of life (<em>ḥayyîm</em>) and strong (<em>ʿāṣĕmû</em>); those who hate me without cause (<em>ḥinnām</em>) have multiplied" — the cruel contrast of v. 19: while the psalmist is near death (vv. 3-10), the enemies are "full of life (<em>ḥayyîm</em>)" — vigorous, healthy, powerful. <em>ʿĀṣam</em> (to be numerous, to be strong, to be mighty) — the same verb used for the multiplication of Israel in Egypt (Exod 1:7, 20). "Without cause (<em>ḥinnām</em>)" — the gratuitous hostility (also Ps 35:7, 19; 69:4; John 15:25 — Jesus applies <em>ḥinnām</em> to the hate of the world against him). The unjust prosperity of the enemy alongside the unjust suffering of the righteous is the theodicy tension the psalm refuses to resolve by denying either side.</p>',
    "20": '<p>"Those who repay good with evil (<em>mĕšallĕmê rāʿāh taḥaṯ ṭôbāh</em>) oppose me, because I pursue what is right" — the corruption of reciprocity is at its worst when good is repaid with evil. The ancient ANE reciprocity ethic made the exchange of good for evil the most severe breach of social covenant (cf. Prov 17:13; Gen 44:4). "Because I pursue what is right (<em>ʿal-rādĕpî-ṭôb</em>)" — the irony is complete: the psalmist\'s goodness is the occasion of the attack. The righteous suffer precisely because their righteousness exposes and threatens the wicked. This dynamic — righteousness provoking enmity — is the pattern of the Suffering Servant (Isa 53:3-9) and is identified in the NT as the pattern of Christ\'s passion.</p>',
    "21": '<p>"Do not abandon me (<em>al-taʿazbēnî</em>), LORD; my God, do not stay far away (<em>al-tirḥaq</em>)" — the paired petitions of the lament\'s close: non-abandonment and proximity. Both petitions address the fear of divine withdrawal at the moment of greatest need. <em>ʿĀzab</em> (to abandon, to forsake, to leave) is the covenant term for the most severe divine relational act — used in Deuteronomy\'s warnings (Deut 31:6, 8; Josh 1:5) and in the promises of Isa 41:17; 42:16; 49:15. The psalmist prays the covenant promise: "I will never leave you nor forsake you" (Deut 31:8). The proximity language ("do not be far") is paired with Jesus\'s cry of dereliction from Ps 22:1: "my God, my God, why have you forsaken me?" — the same language in the same moment of divine hiddenness.</p>',
    "22": '<p>"Come quickly to help me (<em>ḥûšāh lĕʿezrāṯî</em>), O Lord, my salvation (<em>tĕšûʿāṯî</em>)" — the urgent imperative "come quickly" (<em>ḥûš</em>, to hurry) is the emergency register of the lament petition — when time matters, when the situation is desperate (also Pss 22:19; 40:13; 70:1, 5; 71:12; 141:1). "My salvation (<em>tĕšûʿāṯî</em>)" as a divine title — not "the God who saves" but "my salvation itself"; YHWH is identified with the rescue rather than merely its agent. The psalm that opened with a plea not to rebuke (v. 1) closes with a plea for urgent rescue — the movement from fear of divine anger to reliance on divine salvation is the trajectory of penitential prayer.</p>',
  },
  "39": {
    "1": '<p>Psalm 39 is addressed to Jeduthun, one of the three chief Levitical musicians appointed by David (1 Chr 16:41-42; 25:1, 3, 6; 2 Chr 5:12). Jeduthun is associated with a musical style or tradition, though its specific character is lost. The psalm is one of the Psalter\'s most existentially searching meditations: it opens with the psalmist\'s resolution to silence and ends with a request that God look away — both the opposite of typical lament conventions. "I will keep watch over my ways (<em>ʾešmĕrāh dĕrākay</em>) so I will not sin with my tongue" — the restraint of speech is a wisdom discipline (Prov 13:3; 21:23; Jas 3:2); the specific concern here is not to sin verbally in the presence of the wicked. The muzzle metaphor ("muzzle over my mouth while the wicked are in front of me") — <em>maḥsôm</em> (muzzle, bridle) — is unique in the Psalter: the psalmist bridles his own mouth as one bridles an animal, preventing speech that might dishonor God or give the wicked an advantage.</p>',
    "2": '<p>"I was mute (<em>neʾĕlamtî</em>) and utterly silent (<em>dûmiyyāh</em>), holding back even from what was good (<em>miṭṭôb</em>), and my pain intensified (<em>nĕʿkār kaʾăbî</em>)" — the complete, self-imposed silence extends even to "good" speech — not just avoiding sinful complaints but suppressing even appropriate expression of suffering. <em>Dûmiyyāh</em> (silence, stillness) is the deepest form of silence (also Ps 62:1: "For God alone my soul waits in silence"). The paradox: the discipline of silence intended to prevent sin actually intensified the pain (<em>kaʾab</em>, to be in pain, to ache). Suppression of suffering does not relieve it; the psalmist discovers that silence was not the answer. The resolution comes in v. 3 when the inner fire finally breaks out in speech.</p>',
    "3": '<p>"My heart grew hot (<em>ḥam-libbî</em>) within me; as I brooded (<em>bĕhagîgî</em>), the fire blazed up; then I spoke (<em>dibbartî</em>) with my tongue" — three stages: heating, conflagration, eruption into speech. <em>Hāgāh</em> (to brood, to meditate, to mutter) — the inward meditation of the Psalter (Ps 1:2; 37:30; 77:12) here produces heat rather than comfort; the brooding intensifies the fire rather than cooling it. Jeremiah 20:9 describes the identical experience: "If I say \'I will not mention him or speak any more in his name,\' his word is in my heart like a fire, a fire shut up in my bones. I am weary of holding it in; indeed, I cannot." The compulsive breaking of the silence — the fire that cannot be contained — is what produces the prayer of vv. 4-13.</p>',
    "4": '<p>"LORD, show me my end (<em>qiṣṣî</em>) — how long I have to live; let me grasp how short-lived I am (<em>mah-ḥādēl ʾānî</em>)" — an unusual prayer: the psalmist asks not for longer life but for clear knowledge of life\'s brevity. <em>Qēṣ</em> (end, limit) — the terminus of one\'s existence. <em>Ḥādēl</em> (fleeting, transient, that which ceases) — from <em>ḥādal</em> (to stop, to cease, to desist). The request is for the wisdom of mortality: Ps 90:12 prays "teach us to number our days so that we may gain a heart of wisdom." The ANE wisdom tradition (Egyptian, Mesopotamian, and Israelite) frequently used meditation on death as the path to wise living. The psalmist doesn\'t want to avoid death but to grasp it so clearly that it reorients the present.</p>',
    "5": '<p>"You have made my days barely a handbreadth (<em>ṭĕpāḥôṯ</em>) long; my lifetime is as nothing in your sight. Truly every person at their best is only a breath (<em>hebel</em>). Selah" — <em>ṭepah</em> (handbreadth) — the smallest standard unit of Hebrew measurement, approximately 3 inches (7-8 cm), the width of four fingers. Human life measured in handbreadths before the eternal God is almost unmeasurably small. <em>Hebel</em> (breath, vapor, emptiness, vanity) — the central term of Ecclesiastes (Eccl 1:2: "vanity of vanities, all is vanity"; <em>hakkōl hebel</em>). The word occurs twelve times in Ecclesiastes alone and is the thematic organizing concept of that book. Here it appears twice (vv. 5, 11) — Psalm 39 and Ecclesiastes share the same mortality vocabulary and perspective. "Selah" — a liturgical pause, giving space for the weight of this observation to settle.</p>',
    "6": '<p>"Surely everyone moves about like a shadow (<em>ṣelem</em>); they are in commotion (<em>yehĕmāyûn</em>) for nothing; they pile up wealth and do not know who will collect it (<em>yĕʾaspēm</em>)" — three observations on the futility of <em>hebel</em>-existence. <em>Ṣelem</em> (shadow, image, likeness) is used in Gen 1:26-27 for humans as made "in the image (<em>ṣelem</em>) of God" — the identical word here reduced to a shadow in motion. The irony is sharp: the creature made in the divine image turns out to be a shadow. "Commotion for nothing" — the busy anxiety (<em>hāmāh</em>, to be in turmoil, to roar, to murmur) of human economic and social striving. "They pile up wealth and do not know who will collect it" — Eccl 2:18-21; 4:8; Luke 12:20 ("fool, tonight your soul is required of you, and the things you have prepared, whose will they be?"). The accumulation anxiety is universal and universally futile.</p>',
    "7": '<p>"And now, Lord, what do I wait for (<em>mah-qiwwîṯî</em>)? My hope (<em>tôḥalṯî</em>) is in you" — the pivot of the meditation: having established the utter transience of human life (vv. 4-6), the psalmist\'s question is "what then is worth waiting for?" The answer is not a what but a Who. <em>Qāwāh</em> (to wait, to hope with tension like a taut cord) and <em>yāḥal</em> (to hope, to wait with expectation) — both hope-words appear in close proximity, reinforcing that the only stable object of hope in a <em>hebel</em>-world is YHWH himself. This is the existential move of the Psalter against the futility perspective: not denial of transience (v. 5 is not retracted) but reorientation of hope from temporal possessions to the eternal God.</p>',
    "8": '<p>"Rescue me from all my transgressions (<em>pĕšāʿay</em>); do not make me a disgrace (<em>ḥerpāh</em>) before fools (<em>nābāl</em>)" — the petition moves from mortality-meditation back to the specific crisis of the opening verse. <em>Pešaʿ</em> (transgression, rebellion, covenant breach) is the broadest and most severe term for sin — deliberate defection. <em>Nābāl</em> (fool) is the wisdom tradition\'s term for the morally and practically bankrupt person — not intellectual but ethical: the one who acts as if God does not exist or does not matter (Ps 14:1: "the fool says in his heart, \'There is no God\'"). The psalmist prays to be spared the shame of being a spectacle for fools — the double shame of being simultaneously a sinner and publicly humiliated before those who would use that humiliation to mock God.</p>',
    "9": '<p>"I am silent (<em>neʾĕlamtî</em>); I do not open my mouth (<em>lōʾ ʾepṣeh-pî</em>), because this is your doing (<em>kî ʾattāh ʿāśîṯā</em>)" — the silence of v. 2 returns, but transformed. In v. 2, the silence was strategic discipline; in v. 9, after the eruption of speech (vv. 3-12), the silence is theological acceptance: "because you have done this." The psalmist acknowledges YHWH\'s agency in his suffering — not mechanically (as if suffering were deserved), but covenantally: the God who acts in history has acted here, and the speaker accepts that. This is the Job-posture: "The LORD gave, and the LORD has taken away; blessed be the name of the LORD" (Job 1:21).</p>',
    "10": '<p>"Take away (<em>hāsēr</em>) your affliction from me; I am worn down (<em>kālîṯî</em>) by the blow (<em>tigrāṯ</em>) of your hand" — having accepted divine agency (v. 9), the psalmist now petitions for relief. This is not contradiction but honest covenantal dialogue: acceptance of divine action does not preclude petition against it. Job exhibits the same pattern (Job 1:21 followed by Job 3:1). <em>Kālāh</em> (to be spent, to be completed, to be exhausted) describes the complete depletion of energy and resources (Ps 71:9; 102:3; Isa 40:28). "The blow (<em>tigrāh</em>) of your hand" — <em>tigrāh</em> is a hapax (unique occurrence), possibly related to <em>gāraʿ</em> (to diminish, to take away) or to a root meaning "blow, stroke." The tactile image of the divine hand striking the psalmist is the same as v. 2\'s "your hand has come down hard on me."</p>',
    "11": '<p>"When you correct (<em>bĕtôkāḥôṯ</em>) someone for their iniquity with rebukes, you consume like a moth (<em>kāʿāš bālîṯā</em>) everything they prize; truly every person is only a breath (<em>hebel</em>). Selah" — <em>tôkēḥāh</em> (correction, proof, rebuke) is the term for the wise person\'s authoritative rebuke that produces change (Prov 1:23, 25, 30; 3:11; 5:12; 10:17; 12:1; 13:18). "Consume like a moth" — the moth as destroyer of precious garments (Isa 51:8; Job 13:28; Matt 6:19; Jas 5:2) is the image of silent, invisible, gradual consumption that reduces what was prized to nothing. The moth-consumed garment ends as <em>hebel</em>. Second "Selah" — the second pause around the <em>hebel</em> statement reinforces its weight in the psalm\'s structure.</p>',
    "12": '<p>"Hear my prayer (<em>šimʿāh ṯĕpillāṯî</em>), LORD, and listen to my cry; do not stay silent (<em>al-teḥĕraš</em>) at my tears (<em>dimeʿāṯî</em>). I am a stranger (<em>gēr</em>) in your presence, a temporary traveler (<em>tôšāb</em>), as all my ancestors were" — the legal pair <em>gēr wĕtôšāb</em> (resident alien and temporary sojourner) is the standard OT designation for those with no land-rights in the community (Lev 25:23, 35, 47; Gen 23:4; 1 Chr 29:15). Abraham used this self-description before the Hittites (Gen 23:4); Isaac is a sojourner (Gen 26:3); the patriarchs generally "sojourned" rather than owning the promised land (Heb 11:13-16 takes this up explicitly: "they admitted that they were strangers and exiles on the earth"). To be a <em>gēr</em> before YHWH is to acknowledge that one\'s very presence in the covenant community is a gracious gift, not an inherent right. The appeal to ancestors connects the psalmist to the whole patriarchal tradition of dependent sojourning.</p>',
    "13": '<p>"Turn your gaze (<em>tašaʿ</em>) from me, so that I may recover joy (<em>wĕʾabĕlîgāh</em>) before I depart and am gone (<em>ʾênenî</em>)" — the most paradoxical petition of the entire psalm: rather than the usual "look at me, help me," the psalmist asks YHWH to look away. <em>Šāʿāh</em> (to look at, to gaze upon) — divine looking is experienced not as comfort but as intensifying scrutiny, like the divine gaze in Job 7:17-19: "What is man that you make so much of him... examine him every morning and test him every moment? Will you never look away from me?" The request for a moment\'s relief from divine attention — "so that I may recover joy before I die" — is the most honest expression of the human experience of divine scrutiny in the Psalter. The psalm that opened with voluntary silence ends with a request for a moment of unseen-ness: brief relief, a breath of freedom before the inevitable end.</p>',
  },
  "40": {
    "1": '<p>Psalm 40 is structurally unusual: it combines a completed thanksgiving (vv. 1-10) for a past deliverance with a new lament petition (vv. 11-17), suggesting either that the same person experiences a new crisis after being delivered, or (more likely) that the psalm is designed for repeated liturgical use by anyone who has been delivered and now faces a new crisis. The superscription "To the director of music, A Psalm of David" places it in the royal liturgical collection. "I waited patiently (<em>qawwōh qiwwîṯî</em>)" — the cognate infinitive absolute for emphasis: "waiting, I waited," i.e., I waited with determined perseverance. <em>Qāwāh</em> (to wait with hope, tension like a rope stretched taut) is the patience-virtue of Ps 37 applied here as biographical testimony: "I did what Ps 37 commanded, and YHWH responded."</p>',
    "2": '<p>"He lifted me out of the pit of destruction (<em>bôr šāʾôn</em>) from the muddy bog (<em>tît hayyāwēn</em>); he set my feet on a rock (<em>seleʿ</em>) and made my steps firm" — <em>bôr šāʾôn</em> (pit of noise/destruction) — the underworld imagery of Sheol, the pit of death (also Pss 88:3-6; 143:3; Lam 3:53-55; Isa 38:17-18). <em>Tît hayyāwēn</em> (miry clay, muddy bog) — the sinking quicksand-like mud of the riverbed; the same imagery as Ps 69:2, 14 ("I sink in the deep mire"). The rescue from the pit is simultaneously personal (from illness, danger, or despair) and eschatological (from the realm of death itself). "Set my feet on a rock (<em>seleʿ</em>)" — the contrast between the bog and the rock is total: the unstable, sinking surface replaced by the immovable foundation. <em>Seleʿ</em> (rock, cliff) is also used as a divine title (Pss 18:2; 19:14; 31:2-3).</p>',
    "3": '<p>"He put a new song (<em>šîr ḥādāš</em>) in my mouth, praise to our God; many will see and be filled with awe (<em>yîrāʾû</em>) and will put their trust in the LORD" — the <em>šîr ḥādāš</em> (new song) is a recurring motif in the Psalter (Pss 33:3; 40:3; 96:1; 98:1; 144:9; 149:1; Isa 42:10; Rev 5:9; 14:3) for the song of fresh divine deliverance. Each new act of rescue requires a new song because the old songs do not capture the particular character of the new event. "Many will see and be filled with awe" — the public dimension of private deliverance: the testimony of the rescued one becomes the occasion for others\'s faith (cf. Ps 22:27-28, 31). The public thanksgiving psalm is a community event: the rescued person\'s testimony functions as evangelion — good news that produces trust in others.</p>',
    "4": '<p>"Blessed is the one who makes the LORD his trust (<em>mibṭaḥô</em>) and does not turn to the proud (<em>rĕhābîm</em>) or to those who follow falsehood (<em>śāṭê kāzāb</em>)" — the beatitude form connecting trust-in-YHWH with avoiding two alternative orientations. <em>Rĕhābîm</em> (the proud, the arrogant) — from <em>rāhab</em> (to act stormily, to be arrogant, to storm); in Ps 89:10 <em>Rĕhab</em> is the mythological sea-monster crushed by YHWH (also Isa 51:9). To trust in the proud is to trust in the chaos-forces that YHWH defeats. <em>Śāṭê kāzāb</em> (those who turn aside to falsehood) — idolaters who turn to <em>šeqer</em> (falsehood) are turning to non-gods, the same contrast Ps 31:6 makes: "those who cling to empty vanities abandon the steadfast love that belongs to them."</p>',
    "5": '<p>"You have multiplied your wonderful deeds (<em>niplĕʾôtêkā</em>) and your thoughts (<em>maḥšĕbôtêkā</em>) toward us, O LORD my God; no one can compare to you. If I were to declare and speak them, they are too many to count" — the hymnic response to overwhelming divine grace. <em>Niplāʾôt</em> (wonderful works, miracles, marvels) — the category of acts so beyond human power and expectation that they require a new vocabulary; used for the Exodus signs (Exod 3:20; 34:10; Ps 78:12), creation (Ps 136:4), and ongoing providence. "Your thoughts toward us (<em>maḥšĕbôtêkā ʾēlênû</em>)" — divine intentionality, the active mental engagement of God with his people; Jer 29:11: "I know the plans (<em>maḥšābôt</em>) I have for you, plans for shalom and not for harm." The incomparability formula (<em>mî kāmôkā</em>, "none compares to you") appears in Exod 15:11; Ps 35:10; Isa 40:18; 46:5; Mic 7:18.</p>',
    "6": '<p>"Sacrifice (<em>zebaḥ</em>) and grain offering (<em>minḥāh</em>) you did not want; but you have given me opened ears (<em>ʾoznayim kārîṯā lî</em>); burnt offering (<em>ʿôlāh</em>) and sin offering (<em>ḥaṭṭāʾāh</em>) you have not asked for" — the most theologically freighted verse of the psalm. Four cultic categories are listed and negated: the <em>zebaḥ</em> (peace offering/slaughter), the <em>minḥāh</em> (grain offering), the <em>ʿôlāh</em> (whole burnt offering), and the <em>ḥaṭṭāʾāh</em> (sin offering) — together they cover the major sacrifice types. The negation is not an anti-temple polemic (as Amos 5:21-25 might be read) but a relativization: what God truly desires is not these per se but what they are meant to express — the obedient heart. "Opened ears" (<em>ʾoznayim kārîṯā</em>, literally "ears you have dug/bored for me") — possibly an allusion to the ear-piercing of the lifelong servant (Exod 21:6; Deut 15:17), or simply "you have made me receptive to your instruction." The Septuagint (LXX) renders this as "a body you have prepared for me" — a significant divergence that Heb 10:5-7 applies to Christ.</p>',
    "7": '<p>"Then I said, \'Here I am; in the scroll of the book (<em>bĕmĕgillat-sēper</em>) it is written about me\'" — the "here I am" (<em>hinnēh-bāʾṯî</em>, I have come) is the classic response of readiness and availability (Gen 22:1, 7, 11 — Abraham\'s response to the divine summons; Isa 6:8 — Isaiah\'s response to the divine call). "The scroll of the book" — likely the Torah scroll (cf. Deut 17:18-20, the king\'s copy of the law); the psalmist presents his existence as already inscribed in the divine purposes contained in the Torah. Heb 10:7 quotes this verse (following the LXX) as Christ\'s words at his incarnation: "Then I said, \'Behold, I have come to do your will, O God, as it is written of me in the scroll of the book.\'" The christological application reads the "here I am" as Christ\'s entry into the world in perfect obedience to the will expressed in Scripture.</p>',
    "8": '<p>"I delight (<em>ḥāpāṣtî</em>) to do your will, O my God; your instruction (<em>tôrātĕkā</em>) is within my heart (<em>bĕṯôk mēʿāy</em>)" — the positive counterpart of v. 6\'s negations: not external sacrifice but inward delight in obedience. <em>Ḥāpēṣ</em> (to delight in, to desire, to take pleasure in) — the word used for YHWH\'s "not delighting in" sacrifice in v. 6 is here used for the speaker\'s delight in YHWH\'s will — a mirroring. "Your instruction (<em>tôrāh</em>) within my heart (<em>bĕtôk mēʿāy</em>)" — the internalization of Torah promised in Jer 31:33 ("I will put my law within them") and described as the goal of Ps 37:31. The word <em>mēʿîm</em> (innermost parts, bowels, womb) indicates the deepest level of the person — not intellectual assent but the depths of the being transformed by Torah. Heb 10:7 applies this to Christ: the incarnate Son\'s delight in doing the Father\'s will is the fulfillment of the psalmist\'s aspiration.</p>',
    "9": '<p>"I have announced (<em>bissartî</em>) righteousness in the great assembly (<em>bĕqāhāl rāb</em>); I have not held my lips back — LORD, you know it" — <em>bāsar</em> (to bring good news, to announce, to herald) — the verbal root of <em>bĕśôrāh</em> (good news, gospel) and the Septuagint\'s <em>euangelizomai</em> (to evangelize, to proclaim the gospel). The righteous proclamation (<em>ṣedeq</em>) announced in the great assembly is the public declaration of deliverance — the thanksgiving psalm as public gospel. The "great assembly" is the congregation gathered at the temple, the same context as the todah (thanksgiving offering). "LORD, you know it" — the divine witness to the psalmist\'s public obedience; the same appeal to divine knowledge as Ps 139:1-4.</p>',
    "10": '<p>"I have not hidden your righteousness (<em>ṣidqāṯĕkā</em>) in my heart; I have declared your faithfulness (<em>ʾĕmûnāṯĕkā</em>) and your salvation (<em>tĕšûʿāṯĕkā</em>); I have not concealed your steadfast love (<em>ḥasdĕkā</em>) or your truth (<em>wĕʾamiṯĕkā</em>) from the great assembly" — five divine attributes named and proclaimed: righteousness, faithfulness, salvation, steadfast love, and truth. These five together constitute the core vocabulary of YHWH\'s covenant character (cf. Ps 36:5-6 where four of these appear). The five-fold "I have not hidden... I have not concealed" structure is a testimony of complete transparency — the psalmist has not withheld any dimension of the divine character from the public proclamation. This is the anti-concealment, the opposite of the "hiding" that characterizes the wicked (Ps 36:4; 52:2).</p>',
    "11": '<p>"As for you, LORD, do not withhold your compassion (<em>raḥămêkā</em>) from me; let your steadfast love and truth continually protect me" — the transition from thanksgiving (vv. 1-10) to petition (vv. 11-17) is marked by "As for you" (<em>ʾattāh</em>) — a pivot from the psalmist\'s proclamation of what YHWH has done to a new petition for what YHWH should do. "Your compassion (<em>raḥămêkā</em>)" — <em>raḥam</em> (womb-compassion, tender mercy) is YHWH\'s maternal emotion, the feeling of a parent for the child borne in the womb (Isa 49:15: "Can a mother forget the baby at her breast and have no compassion on the child she has borne?"). The accumulated attributes — compassion, <em>ḥesed</em>, truth — form a request that the same divine character that was proclaimed (vv. 9-10) now be directed personally toward the speaker in the new crisis.</p>',
    "12": '<p>"For countless evils (<em>rāʿôt ʾên-mispar</em>) have closed in around me (<em>ʾăpāpûnî</em>); my iniquities (<em>ʿăwōnōṯay</em>) have caught up with me (<em>hissîgûnî</em>) until I cannot see clearly (<em>ʿad-lōʾ-yākolṯî lirʾôṯ</em>)" — the new crisis is described with the same surrounding-and-overwhelming imagery as Ps 38\'s illness (Ps 38:4, 8). The admission that "my iniquities have caught up with me" is one of the Psalter\'s honest acknowledgments that the speaker\'s own sins contribute to the crisis. "Until I cannot see clearly" — the inability to see is both physical (despair darkens the perception) and moral (sin distorts the vision). "They are more than the hairs of my head (<em>rabbû miśśaʿărôt rōʾšî</em>)" — the proverbial uncountability of hair (Gen 16:10; Luke 12:7; Acts 27:34) applied to sins and troubles; the human cannot number them but God can.</p>',
    "13": '<p>"Please, LORD, come to rescue me; LORD, hurry to help me (<em>ḥûšāh lĕʿezrāṯî</em>)" — verses 13-17 of Psalm 40 are virtually identical to Psalm 70 (with minor textual variations), which circulates independently as a shorter emergency petition. The appearance of a complete independent psalm within Psalm 40 raises questions about composition: either Ps 40 incorporates an older petition (Ps 70), or Ps 70 is an excerpt from Ps 40, or both draw on a common liturgical prayer. The "hurry to help me" (<em>ḥûšāh lĕʿezrāṯî</em>) prayer appears in Pss 22:19; 38:22; 71:12 — an emergency formula for urgent divine assistance. The liturgical portability of the petition (usable independently as Ps 70) suggests it was a standard emergency prayer in the temple liturgy.</p>',
    "14": '<p>"Let those who seek to take my life be put to shame and confounded (<em>yēbōšû wĕyaḥpĕrû</em>); let those who wish me harm be turned back in disgrace (<em>yissōgû ʾāḥôr wĕyikālamû</em>)" — the double shame-pair: <em>bôš</em> (shame, confusion) and <em>ḥāpar</em> (to be ashamed, to be embarrassed) in the first pair; <em>sûg ʾāḥôr</em> (turn backward, retreat) and <em>kālam</em> (be humiliated, disgraced) in the second. All four terms describe the public reversal of honor — the enemy who confidently sought the psalmist\'s life being publicly exposed, turned back, and shamed in the community\'s sight. The honor-shame reversal is the social dimension of divine vindication: not merely the psalmist\'s private survival but the public demonstration of the enemy\'s miscalculation.</p>',
    "15": '<p>"Let those who mock me with \'Aha! Aha!\' (<em>heʾāḥ heʾāḥ</em>) be horrified by their own shame" — the gloating exclamation <em>heʾāḥ</em> appears in Pss 35:21, 25 and Ezek 25:3; 26:2; 36:2 — always the triumphant cry of one who gloats over another\'s ruin. The prayer that those who gloat will be "horrified (<em>yāšōmmû</em>) by their own shame" is the shame-reversal petition: the emotion they intended to produce in the psalmist (horror, shock) lands on themselves instead. <em>Šāmam</em> (to be desolate, to be devastated, to be appalled) is one of the strongest shock-responses in Hebrew — the same verb used for the desolation of the temple after the destruction (Lam 1:4, 13, 16) and for the Servant\'s appearance that "appalled" many (Isa 52:14).</p>',
    "16": '<p>"Let all who seek you (<em>mĕbaqqĕšêkā</em>) rejoice and be glad in you; let those who love your salvation (<em>tĕšûʿāṯĕkā</em>) always say, \'Great is the LORD!\'" — the positive counterpart to vv. 14-15\'s shame-petitions. While the wicked are shamed, "all who seek you" (the covenant community of <em>dōrĕšê YHWH</em>) will rejoice. The seeking (<em>bāqaš</em>) of God is the positive covenant orientation — actively pursuing the divine presence (Amos 5:4-6; Isa 55:6-7; Ps 27:4, 8). "Those who love your salvation" — the community\'s love for <em>tĕšûʿāh</em> (salvation) is the communal counterpart of the psalmist\'s personal experience of rescue (vv. 1-3). "Great is the LORD!" — the proclamation that emerges from witnessed deliverance; the same shout that accompanies the ark procession (2 Sam 6:2) and the divine enthronement psalms (Pss 47:2; 95-100).</p>',
    "17": '<p>"As for me, I am poor (<em>ʿānî</em>) and needy (<em>ʾebyôn</em>); yet the Lord thinks of me (<em>yaḥšōb</em>). You are my help and my deliverer — do not be slow (<em>al-ʾaḥar</em>), my God" — the final verse holds together the psalmist\'s poverty and the Lord\'s intentional attention. <em>ʿĀnî wĕʾebyôn</em> (poor and needy) — the standard paired designation of the socially and economically vulnerable (Ps 37:14 above; Pss 35:10; 70:5; 86:1; 109:22; Isa 41:17; Amos 4:1; 8:4, 6). "Yet the Lord thinks of me (<em>yaḥšōb lî ʾădōnāy</em>)" — the divine thought (<em>ḥāšab</em>) directed toward the poor person is the theodicy resolution compressed into one line: the great God who has "multiplied wonderful deeds and thoughts toward us" (v. 5) also specifically thinks of the individual poor person. Ps 70 ends with the same verse, confirming it as the standard emergency-close of this petition type. "Do not be slow (<em>al-ʾaḥar</em>)" — the urgent "do not delay" that brings the psalm to its final note of urgent, hopeful prayer.</p>',
  },
}

def main():
    existing = load_comm('mkt-context', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-context', 'psalms', existing)
    print('Psalms 37–40 mkt-context written.')

if __name__ == '__main__':
    main()
